# CUB API 指定 CUDA Stream 执行

CUB 的 API 支持通过最后一个参数指定 CUDA Stream。以下是 `cub::DeviceRadixSort::SortPairs` 的使用方法：

## 基本语法

```cpp
#include <cub/cub.cuh>

// 1. 确定临时存储空间大小
void* d_temp_storage = nullptr;
size_t temp_storage_bytes = 0;

cub::DeviceRadixSort::SortPairs(
    d_temp_storage, 
    temp_storage_bytes,
    d_keys_in, 
    d_keys_out,
    d_values_in, 
    d_values_out,
    num_items,
    begin_bit,      // 默认 0
    end_bit,        // 默认 sizeof(KeyT) * 8
    stream          // CUDA Stream
);

// 2. 分配临时存储空间
cudaMalloc(&d_temp_storage, temp_storage_bytes);

// 3. 执行排序
cub::DeviceRadixSort::SortPairs(
    d_temp_storage, 
    temp_storage_bytes,
    d_keys_in, 
    d_keys_out,
    d_values_in, 
    d_values_out,
    num_items,
    begin_bit,
    end_bit,
    stream          // 指定的 CUDA Stream
);
```

## 完整示例

```cpp
#include <cub/cub.cuh>
#include <iostream>

int main() {
    const int num_items = 1000;

    // 创建 CUDA Stream
    cudaStream_t stream;
    cudaStreamCreate(&stream);

    // 分配设备内存
    int *d_keys_in, *d_keys_out;
    int *d_values_in, *d_values_out;
    cudaMalloc(&d_keys_in, num_items * sizeof(int));
    cudaMalloc(&d_keys_out, num_items * sizeof(int));
    cudaMalloc(&d_values_in, num_items * sizeof(int));
    cudaMalloc(&d_values_out, num_items * sizeof(int));

    // 初始化数据（省略）

    // 第一步：查询所需临时存储空间大小
    void* d_temp_storage = nullptr;
    size_t temp_storage_bytes = 0;
    cub::DeviceRadixSort::SortPairs(
        d_temp_storage, temp_storage_bytes,
        d_keys_in, d_keys_out,
        d_values_in, d_values_out,
        num_items,
        0,                              // begin_bit
        sizeof(int) * 8,                // end_bit
        stream                          // 指定 stream
    );

    // 第二步：分配临时存储空间
    cudaMalloc(&d_temp_storage, temp_storage_bytes);

    // 第三步：执行排序
    cub::DeviceRadixSort::SortPairs(
        d_temp_storage, temp_storage_bytes,
        d_keys_in, d_keys_out,
        d_values_in, d_values_out,
        num_items,
        0, sizeof(int) * 8,
        stream                          // 在指定 stream 中执行
    );

    // 等待 stream 完成
    cudaStreamSynchronize(stream);

    // 清理资源
    cudaFree(d_temp_storage);
    cudaFree(d_keys_in);
    cudaFree(d_keys_out);
    cudaFree(d_values_in);
    cudaFree(d_values_out);
    cudaStreamDestroy(stream);

    return 0;
}
```

## 使用 DoubleBuffer（推荐）

```cpp
#include <cub/cub.cuh>

cudaStream_t stream;
cudaStreamCreate(&stream);

// 使用 DoubleBuffer 简化内存管理
cub::DoubleBuffer<int> d_keys(d_keys_in, d_keys_out);
cub::DoubleBuffer<int> d_values(d_values_in, d_values_out);

void* d_temp_storage = nullptr;
size_t temp_storage_bytes = 0;

// 查询大小
cub::DeviceRadixSort::SortPairs(
    d_temp_storage, temp_storage_bytes,
    d_keys, d_values, num_items,
    0, sizeof(int) * 8,
    stream
);

cudaMalloc(&d_temp_storage, temp_storage_bytes);

// 执行排序
cub::DeviceRadixSort::SortPairs(
    d_temp_storage, temp_storage_bytes,
    d_keys, d_values, num_items,
    0, sizeof(int) * 8,
    stream
);

// d_keys.Current() 指向排序后的 keys
// d_values.Current() 指向排序后的 values
```

## 其他 CUB API 的 Stream 参数

其他 CUB 设备级函数也支持 stream 参数：

```cpp
// DeviceReduce
cub::DeviceReduce::Sum(d_temp_storage, temp_storage_bytes, 
                       d_in, d_out, num_items, stream);

// DeviceScan
cub::DeviceScan::ExclusiveSum(d_temp_storage, temp_storage_bytes,
                              d_in, d_out, num_items, stream);

// DeviceSelect
cub::DeviceSelect::Flagged(d_temp_storage, temp_storage_bytes,
                          d_in, d_flags, d_out, d_num_selected,
                          num_items, stream);
```

## 注意事项

1. **Stream 参数是最后一个参数**（在 `begin_bit` 和 `end_bit` 之后）
2. 默认使用 `stream = 0`（默认流）
3. 两次调用都需要指定相同的 stream
4. 使用 `cudaStreamSynchronize(stream)` 等待完成

# 不传 Stream 参数的行为

## 默认行为

如果不传 `stream` 参数，CUB API 会使用 **默认 CUDA Stream (stream 0)**，也称为 **NULL stream**。

```cpp
// 不传 stream，等价于 stream = 0
cub::DeviceRadixSort::SortPairs(
    d_temp_storage, temp_storage_bytes,
    d_keys_in, d_keys_out,
    d_values_in, d_values_out,
    num_items
);

// 等价于显式传入 0
cub::DeviceRadixSort::SortPairs(
    d_temp_storage, temp_storage_bytes,
    d_keys_in, d_keys_out,
    d_values_in, d_values_out,
    num_items,
    0, sizeof(int) * 8,
    0  // 或 cudaStreamDefault
);
```

## 默认 Stream 的特点

### 1. **阻塞行为（Legacy Default Stream）**

默认情况下，stream 0 是 **阻塞流**：

```cpp
cudaStream_t stream1;
cudaStreamCreate(&stream1);

// kernel1 在 stream1 中执行
myKernel<<<grid, block, 0, stream1>>>();

// CUB 操作在默认流中执行
cub::DeviceRadixSort::SortPairs(...);  // 不传 stream

// kernel2 在 stream1 中执行
myKernel<<<grid, block, 0, stream1>>>();
```

**执行顺序：**
- CUB 操作会**等待所有先前的操作**（包括 stream1 中的 kernel1）完成
- CUB 操作完成后，**所有后续操作**（包括 stream1 中的 kernel2）才会开始
- **无法实现真正的并发**

### 2. **Per-Thread Default Stream（可选）**

使用编译选项 `--default-stream per-thread` 可以改变行为：

```bash
nvcc --default-stream per-thread your_code.cu
```

这样每个主机线程有独立的默认流，可以并发执行。

## 对比示例

### ❌ 不传 Stream - 无法并发

```cpp
cudaStream_t stream1, stream2;
cudaStreamCreate(&stream1);
cudaStreamCreate(&stream2);

// 在 stream1 中排序
myKernel<<<grid, block, 0, stream1>>>();

// 在默认流中排序 - 会阻塞！
cub::DeviceRadixSort::SortPairs(
    d_temp_storage1, temp_storage_bytes1,
    d_keys1, d_values1, num_items1
    // 没有传 stream
);

// 在 stream2 中排序 - 必须等待默认流完成
myKernel<<<grid, block, 0, stream2>>>();
```

**执行时间线：**
```
Stream1:  [kernel] --等待--> [等待默认流] --> [kernel]
Default:  -------- [CUB Sort] ----------------->
Stream2:  -------- [等待默认流] ---------------> [kernel]
```

### ✅ 传入 Stream - 可以并发

```cpp
cudaStream_t stream1, stream2;
cudaStreamCreate(&stream1);
cudaStreamCreate(&stream2);

// Stream1: 准备 + 排序
myPrepareKernel<<<grid, block, 0, stream1>>>();
cub::DeviceRadixSort::SortPairs(
    d_temp_storage1, temp_storage_bytes1,
    d_keys1, d_values1, num_items1,
    0, sizeof(int) * 8,
    stream1  // ✓ 指定 stream
);

// Stream2: 准备 + 排序（可以并发）
myPrepareKernel<<<grid, block, 0, stream2>>>();
cub::DeviceRadixSort::SortPairs(
    d_temp_storage2, temp_storage_bytes2,
    d_keys2, d_values2, num_items2,
    0, sizeof(int) * 8,
    stream2  // ✓ 指定 stream
);

// 等待所有完成
cudaStreamSynchronize(stream1);
cudaStreamSynchronize(stream2);
```

**执行时间线：**
```
Stream1:  [prepare] [CUB Sort      ]
Stream2:  [prepare] [CUB Sort      ]  ← 并发执行
时间:     --------- ----------------
```

## 性能影响

```cpp
// 测试代码
cudaEvent_t start, stop;
cudaEventCreate(&start);
cudaEventCreate(&stop);

// 方法1：不传 stream（串行）
cudaEventRecord(start);
cub::DeviceRadixSort::SortPairs(...);  // stream 0
cub::DeviceRadixSort::SortPairs(...);  // stream 0
cudaEventRecord(stop);
cudaEventSynchronize(stop);
// 时间 ≈ T1 + T2

// 方法2：传入不同 stream（并行）
cudaEventRecord(start);
cub::DeviceRadixSort::SortPairs(..., stream1);
cub::DeviceRadixSort::SortPairs(..., stream2);
cudaEventRecord(stop);
cudaEventSynchronize(stop);
// 时间 ≈ max(T1, T2)  （理想情况）
```

## 最佳实践

### ✅ 推荐做法

```cpp
// 1. 创建专用 stream
cudaStream_t compute_stream;
cudaStreamCreate(&compute_stream);

// 2. 始终显式传入 stream
cub::DeviceRadixSort::SortPairs(
    d_temp_storage, temp_storage_bytes,
    d_keys, d_values, num_items,
    0, sizeof(int) * 8,
    compute_stream  // 明确指定
);

// 3. 根据需要同步
cudaStreamSynchronize(compute_stream);
```

### ❌ 避免做法

```cpp
// 不明确意图，难以维护
cub::DeviceRadixSort::SortPairs(
    d_temp_storage, temp_storage_bytes,
    d_keys, d_values, num_items
    // 没有 stream - 使用默认流
);
// 不知道是否会阻塞其他操作
```

## 总结

| 特性 | 不传 Stream | 传入 Stream |
|------|------------|------------|
| 使用的流 | 默认流 (stream 0) | 指定的流 |
| 并发性 | **阻塞所有其他流** | 可以并发执行 |
| 性能 | 串行执行 | 可以并行优化 |
| 可控性 | 低 | 高 |
| 推荐度 | ❌ 不推荐 | ✅ 推荐 |

**建议：始终显式传入 stream 参数**，即使是使用默认流也写成 `stream = 0`，这样代码意图更清晰。
